CREATE TYPE "StageKind" AS ENUM ('NORMAL','BOSS'); CREATE TYPE "AiLevel" AS ENUM ('EASY','NORMAL','BOSS'); CREATE TYPE "CurrencyCode" AS ENUM ('GOLD','GEM','DUST');
CREATE TABLE "CampaignChapter"("id" TEXT PRIMARY KEY,"number" INTEGER NOT NULL UNIQUE,"name" TEXT NOT NULL,"description" TEXT NOT NULL);
CREATE TABLE "CampaignStage"("id" TEXT PRIMARY KEY,"chapterId" TEXT NOT NULL REFERENCES "CampaignChapter"("id") ON DELETE CASCADE,"number" INTEGER NOT NULL,"name" TEXT NOT NULL,"kind" "StageKind" NOT NULL DEFAULT 'NORMAL',"aiLevel" "AiLevel" NOT NULL DEFAULT 'EASY',"enemyDeck" JSONB NOT NULL,"rewardGold" INTEGER NOT NULL DEFAULT 100,"rewardDust" INTEGER NOT NULL DEFAULT 0,"bossPhases" JSONB,UNIQUE("chapterId","number"));
CREATE TABLE "UserStageProgress"("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"stageId" TEXT NOT NULL REFERENCES "CampaignStage"("id") ON DELETE CASCADE,"stars" INTEGER NOT NULL DEFAULT 0,"completed" BOOLEAN NOT NULL DEFAULT false,"claimedAt" TIMESTAMP(3),"bestTurns" INTEGER,PRIMARY KEY("userId","stageId"));
CREATE TABLE "UserCurrency"("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"code" "CurrencyCode" NOT NULL,"balance" INTEGER NOT NULL DEFAULT 0,PRIMARY KEY("userId","code"));
CREATE TABLE "Pack"("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"priceGold" INTEGER NOT NULL,"faction" "Faction","guaranteed" "Rarity","enabled" BOOLEAN NOT NULL DEFAULT true);
CREATE TABLE "PackSlot"("id" TEXT PRIMARY KEY,"packId" TEXT NOT NULL REFERENCES "Pack"("id") ON DELETE CASCADE,"position" INTEGER NOT NULL,"rarityWeights" JSONB NOT NULL,UNIQUE("packId","position"));
CREATE TABLE "PackOpenHistory"("id" TEXT PRIMARY KEY,"requestId" TEXT NOT NULL,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"packId" TEXT NOT NULL REFERENCES "Pack"("id"),"seedRef" TEXT NOT NULL,"result" JSONB NOT NULL,"pityBefore" INTEGER NOT NULL,"pityAfter" INTEGER NOT NULL,"openedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("userId","requestId"));
CREATE INDEX "PackOpenHistory_userId_packId_openedAt_idx" ON "PackOpenHistory"("userId","packId","openedAt");
CREATE TABLE "PackPity"("userId" TEXT NOT NULL,"packId" TEXT NOT NULL,"epicMisses" INTEGER NOT NULL DEFAULT 0,"legendaryMisses" INTEGER NOT NULL DEFAULT 0,PRIMARY KEY("userId","packId"));
